-- ============================================================================
-- RF-054 — pgTAP: authorization (who may record a cash payment)
-- ============================================================================
-- record_payment authorizes via the PIN session (actor + scope derived server-
-- side, never from the client). cashier/manager/restaurant_owner/org_owner may
-- pay; kitchen_staff and accountant (read-only, D-028) are DENIED — the denied
-- path writes a payment.denied audit and RETURNS permission_denied (no raise, so
-- the audit persists) with NO payment, NO receipt number, NO order mutation, NO
-- ledger write. An order in another branch is rejected (cross-scope impossible).
-- Fixtures inserted as the BYPASSRLS connection role.
-- ============================================================================
begin;
create extension if not exists pgtap with schema extensions;
set local search_path to extensions, public, pg_catalog;

select plan(12);

-- ---- one org / one restaurant / two branches -------------------------------
-- six roles in branch 1
-- a PIN session per role (branch 1, device session 05a1) + one cross-branch session (branch 2)
-- orders: one per success/denied role in branch 1, plus one in branch 2 (cross-scope)

-- RF-055: record_payment now requires an open shift + active cash drawer (A2).
-- Opened by the cashier (ef001/ab01) on branch 1 / device da11; covers all b1 payments.

-- authorized roles succeed -------------------------------------------------- 1-4
select is((app.record_payment('00000000-0000-0000-0000-0000000005c1','00000000-0000-0000-0000-00000000ad01','00000000-0000-0000-0000-00000000da11','z-p-ca','cash',1000,null) ->> 'ok')::boolean, true, 'cashier may record a cash payment');
select is((app.record_payment('00000000-0000-0000-0000-0000000005c2','00000000-0000-0000-0000-00000000ad02','00000000-0000-0000-0000-00000000da11','z-p-mg','cash',1000,null) ->> 'ok')::boolean, true, 'manager may record a cash payment');
select is((app.record_payment('00000000-0000-0000-0000-0000000005c3','00000000-0000-0000-0000-00000000ad03','00000000-0000-0000-0000-00000000da11','z-p-ro','cash',1000,null) ->> 'ok')::boolean, true, 'restaurant_owner may record a cash payment');
select is((app.record_payment('00000000-0000-0000-0000-0000000005c4','00000000-0000-0000-0000-00000000ad04','00000000-0000-0000-0000-00000000da11','z-p-oo','cash',1000,null) ->> 'ok')::boolean, true, 'org_owner may record a cash payment');

-- kitchen_staff + accountant are denied (returned, not raised) -------------- 5-6
select is(app.record_payment('00000000-0000-0000-0000-0000000005c5','00000000-0000-0000-0000-00000000ad05','00000000-0000-0000-0000-00000000da11','z-p-ks','cash',1000,null) ->> 'error', 'permission_denied', 'kitchen_staff is denied (permission_denied)');
select is(app.record_payment('00000000-0000-0000-0000-0000000005c6','00000000-0000-0000-0000-00000000ad06','00000000-0000-0000-0000-00000000da11','z-p-ac','cash',1000,null) ->> 'error', 'permission_denied', 'accountant is denied (D-028, read-only)');

-- the denied path made NO mutation ------------------------------------------ 7-9
select is((select count(*) from payments where order_id='00000000-0000-0000-0000-00000000ad05')::int, 0, 'kitchen_staff denial created NO payment row');
select is((select receipt_number from orders where id='00000000-0000-0000-0000-00000000ad05'), null, 'kitchen_staff denial assigned NO receipt number');
select is((select status from orders where id='00000000-0000-0000-0000-00000000ad05')::text, 'submitted', 'kitchen_staff denial left the order status unchanged');

-- the denied path was audited ----------------------------------------------- 10
select is((select count(*) from audit_events where action='payment.denied')::int, 2, 'both denials wrote a payment.denied audit row');

-- an order in another branch is rejected (cross-scope impossible) ----------- 11
select throws_ok($$ select app.record_payment('00000000-0000-0000-0000-0000000005c1','00000000-0000-0000-0000-00000000ad07','00000000-0000-0000-0000-00000000da11','z-p-x','cash',1000,null) $$, '42501', NULL, 'a cashier cannot pay an order in another branch (cross-scope rejected)');

-- the denied path wrote NO idempotency ledger row --------------------------- 12
select is((select count(*) from order_operations where action='record_payment' and local_operation_id in ('z-p-ks','z-p-ac'))::int, 0, 'a denied payment writes NO order_operations ledger row');

select * from finish();
rollback;
